example.code:
IButton button = ...
button.OnClick += (e) => {
	Debug.Log("button clicked, mouseButton: " + e.MouseButton);
};

IButton button = ...
button.OnMouseEnter += (e) => {
	Debug.Log("mouse entered button");
};

IButton button = ...
button.OnMouseLeave += (e) => {
	Debug.Log("mouse left button");
};
